import sys
MOD = 998244353

def mod_pow(a, e):
    r = 1
    while e:
        if e & 1:
            r = r * a % MOD
        a = a * a % MOD
        e >>= 1
    return r

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    total = 1
    for i in range(N):
        total = total * (239 - i) % MOD
    all_zero = True
    for _ in range(N):
        a = int(next(it))
        if a % 239 != 0:
            all_zero = False
    if not all_zero:
        inv239 = mod_pow(239, MOD - 2)
        total = total * inv239 % MOD
    print(total)

if __name__ == "__main__":
    main()

